# Trie Implementation in C++ using std::vector

Here's a complete implementation of a Trie data structure using `std::vector`:

```cpp
#include <iostream>
#include <vector>
#include <string>
using namespace std;

class TrieNode {
public:
    vector<TrieNode*> children;  // 26 pointers for 'a' to 'z'
    bool isEndOfWord;            // marks end of a word

    TrieNode() : children(26, nullptr), isEndOfWord(false) {}
};

class Trie {
private:
    TrieNode* root;

public:
    // Constructor
    Trie() {
        root = new TrieNode();
    }

    // Insert a word into the trie
    void insert(const string& word) {
        TrieNode* node = root;

        for (char ch : word) {
            int index = ch - 'a';  // Convert character to index (0-25)

            // Create new node if it doesn't exist
            if (node->children[index] == nullptr) {
                node->children[index] = new TrieNode();
            }

            node = node->children[index];
        }

        node->isEndOfWord = true;  // Mark end of word
    }

    // Search for a complete word in the trie
    bool search(const string& word) const {
        TrieNode* node = findNode(word);
        return node != nullptr && node->isEndOfWord;
    }

    // Check if there is any word in the trie that starts with the given prefix
    bool startsWith(const string& prefix) const {
        return findNode(prefix) != nullptr;
    }

    // Delete a word from the trie
    bool deleteWord(const string& word) {
        return deleteHelper(root, word, 0);
    }

    // Destructor - free allocated memory
    ~Trie() {
        deleteTrieHelper(root);
    }

private:
    // Helper function to find a node corresponding to a word/prefix
    TrieNode* findNode(const string& word) const {
        TrieNode* node = root;

        for (char ch : word) {
            int index = ch - 'a';

            if (node->children[index] == nullptr) {
                return nullptr;
            }

            node = node->children[index];
        }

        return node;
    }

    // Recursive helper for deletion
    bool deleteHelper(TrieNode* node, const string& word, int index) {
        if (node == nullptr) {
            return false;
        }

        if (index == word.length()) {
            // Word doesn't exist if it's not marked as end of word
            if (!node->isEndOfWord) {
                return false;
            }

            node->isEndOfWord = false;

            // Return true if node has no children (can be deleted)
            for (TrieNode* child : node->children) {
                if (child != nullptr) {
                    return false;
                }
            }
            return true;
        }

        int charIndex = word[index] - 'a';
        TrieNode* childNode = node->children[charIndex];

        if (!deleteHelper(childNode, word, index + 1)) {
            return false;
        }

        // Delete the child node and set pointer to nullptr
        delete childNode;
        node->children[charIndex] = nullptr;

        // Return true if current node can be deleted (no other children)
        if (node->isEndOfWord) {
            return false;  // Don't delete if it's end of another word
        }

        for (TrieNode* child : node->children) {
            if (child != nullptr) {
                return false;
            }
        }
        return true;
    }

    // Helper function to delete the entire trie
    void deleteTrieHelper(TrieNode* node) {
        if (node == nullptr) {
            return;
        }

        for (TrieNode* child : node->children) {
            deleteTrieHelper(child);
        }

        delete node;
    }
};

// Demo/Test
int main() {
    Trie trie;

    // Insert words
    trie.insert("apple");
    trie.insert("app");
    trie.insert("apricot");
    trie.insert("banana");
    trie.insert("band");

    cout << "=== Search Operations ===" << endl;
    cout << "Search 'apple': " << (trie.search("apple") ? "Found" : "Not Found") << endl;
    cout << "Search 'app': " << (trie.search("app") ? "Found" : "Not Found") << endl;
    cout << "Search 'appl': " << (trie.search("appl") ? "Found" : "Not Found") << endl;
    cout << "Search 'banana': " << (trie.search("banana") ? "Found" : "Not Found") << endl;
    cout << "Search 'ban': " << (trie.search("ban") ? "Found" : "Not Found") << endl;

    cout << "\n=== Prefix Search ===" << endl;
    cout << "StartsWith 'app': " << (trie.startsWith("app") ? "Yes" : "No") << endl;
    cout << "StartsWith 'ban': " << (trie.startsWith("ban") ? "Yes" : "No") << endl;
    cout << "StartsWith 'bat': " << (trie.startsWith("bat") ? "Yes" : "No") << endl;

    cout << "\n=== Delete Operations ===" << endl;
    cout << "Delete 'app': " << (trie.deleteWord("app") ? "Deleted" : "Not Found") << endl;
    cout << "Search 'app' after deletion: " << (trie.search("app") ? "Found" : "Not Found") << endl;
    cout << "Search 'apple' after deleting 'app': " << (trie.search("apple") ? "Found" : "Not Found") << endl;

    return 0;
}
```

## Output:
```
=== Search Operations ===
Search 'apple': Found
Search 'app': Found
Search 'appl': Not Found
Search 'banana': Found
Search 'ban': Not Found

=== Prefix Search ===
StartsWith 'app': Yes
StartsWith 'ban': Yes
StartsWith 'bat': No

=== Delete Operations ===
Delete 'app': Deleted
Search 'app' after deletion: Not Found
Search 'apple' after deleting 'app': Found
```

## Key Features:

1. **Insert**: O(m) where m is word length
2. **Search**: O(m) where m is word length
3. **StartsWith**: O(m) prefix matching
4. **Delete**: O(m) with memory cleanup
5. Uses `std::vector<TrieNode*>` for 26 alphabet characters
6. Proper memory management with destructor
7. Handles edge cases in deletion

# Trie Implementation in C++ using std::vector

Here's a complete implementation of a Trie data structure using `std::vector`:

```cpp
#include <iostream>
#include <vector>
#include <string>

using namespace std;

class TrieNode {
public:
    vector<TrieNode*> children;  // 26 children for lowercase letters a-z
    bool isEndOfWord;

    TrieNode() {
        children.resize(26, nullptr);  // Initialize with 26 null pointers
        isEndOfWord = false;
    }
};

class Trie {
private:
    TrieNode* root;

public:
    Trie() {
        root = new TrieNode();
    }

    ~Trie() {
        deleteTrie(root);
    }

    // Insert a word into the trie
    void insert(const string& word) {
        TrieNode* node = root;

        for (char c : word) {
            int index = c - 'a';  // Convert character to index (0-25)

            if (node->children[index] == nullptr) {
                node->children[index] = new TrieNode();
            }
            node = node->children[index];
        }

        node->isEndOfWord = true;  // Mark end of word
    }

    // Search for a complete word
    bool search(const string& word) {
        TrieNode* node = findNode(word);
        return node != nullptr && node->isEndOfWord;
    }

    // Check if there's any word with given prefix
    bool startsWith(const string& prefix) {
        return findNode(prefix) != nullptr;
    }

    // Delete a word from the trie
    bool deleteWord(const string& word) {
        return deleteHelper(root, word, 0);
    }

    // Print all words in the trie
    void printAllWords() {
        string currentWord = "";
        printHelper(root, currentWord);
    }

    // Get all words with a given prefix
    vector<string> getWordsWithPrefix(const string& prefix) {
        vector<string> result;
        TrieNode* node = findNode(prefix);

        if (node == nullptr) {
            return result;
        }

        string currentWord = prefix;
        getWordsHelper(node, currentWord, result);
        return result;
    }

private:
    // Helper function to find a node for a given prefix
    TrieNode* findNode(const string& prefix) {
        TrieNode* node = root;

        for (char c : prefix) {
            int index = c - 'a';

            if (node->children[index] == nullptr) {
                return nullptr;
            }
            node = node->children[index];
        }

        return node;
    }

    // Helper function to delete a word
    bool deleteHelper(TrieNode* node, const string& word, int index) {
        if (index == word.length()) {
            if (!node->isEndOfWord) {
                return false;  // Word doesn't exist
            }

            node->isEndOfWord = false;

            // Check if node has any children
            for (int i = 0; i < 26; i++) {
                if (node->children[i] != nullptr) {
                    return false;  // Node has children, don't delete
                }
            }

            return true;  // Node can be deleted
        }

        int charIndex = word[index] - 'a';

        if (node->children[charIndex] == nullptr) {
            return false;  // Word doesn't exist
        }

        bool shouldDeleteChild = deleteHelper(node->children[charIndex], 
                                              word, index + 1);

        if (shouldDeleteChild) {
            delete node->children[charIndex];
            node->children[charIndex] = nullptr;

            // Delete current node if it's not end of another word and has no children
            if (!node->isEndOfWord) {
                for (int i = 0; i < 26; i++) {
                    if (node->children[i] != nullptr) {
                        return false;
                    }
                }
                return true;
            }

            return false;
        }

        return false;
    }

    // Helper function to print all words
    void printHelper(TrieNode* node, string& currentWord) {
        if (node->isEndOfWord) {
            cout << currentWord << endl;
        }

        for (int i = 0; i < 26; i++) {
            if (node->children[i] != nullptr) {
                currentWord.push_back('a' + i);
                printHelper(node->children[i], currentWord);
                currentWord.pop_back();
            }
        }
    }

    // Helper function to get words with prefix
    void getWordsHelper(TrieNode* node, string& currentWord, vector<string>& result) {
        if (node->isEndOfWord) {
            result.push_back(currentWord);
        }

        for (int i = 0; i < 26; i++) {
            if (node->children[i] != nullptr) {
                currentWord.push_back('a' + i);
                getWordsHelper(node->children[i], currentWord, result);
                currentWord.pop_back();
            }
        }
    }

    // Helper function to delete the entire trie
    void deleteTrie(TrieNode* node) {
        if (node == nullptr) {
            return;
        }

        for (int i = 0; i < 26; i++) {
            if (node->children[i] != nullptr) {
                deleteTrie(node->children[i]);
            }
        }

        delete node;
    }
};

// Driver code with test cases
int main() {
    Trie trie;

    // Insert words
    cout << "Inserting words: apple, app, apricot, banana, band" << endl;
    trie.insert("apple");
    trie.insert("app");
    trie.insert("apricot");
    trie.insert("banana");
    trie.insert("band");

    // Search operations
    cout << "\nSearch Results:" << endl;
    cout << "Searching 'app': " << (trie.search("app") ? "Found" : "Not Found") << endl;
    cout << "Searching 'apple': " << (trie.search("apple") ? "Found" : "Not Found") << endl;
    cout << "Searching 'appl': " << (trie.search("appl") ? "Found" : "Not Found") << endl;

    // Prefix search
    cout << "\nPrefix Search Results:" << endl;
    cout << "Prefix 'ap': " << (trie.startsWith("ap") ? "Found" : "Not Found") << endl;
    cout << "Prefix 'ban': " << (trie.startsWith("ban") ? "Found" : "Not Found") << endl;
    cout << "Prefix 'cat': " << (trie.startsWith("cat") ? "Found" : "Not Found") << endl;

    // Get all words with prefix
    cout << "\nWords with prefix 'ap':" << endl;
    vector<string> words = trie.getWordsWithPrefix("ap");
    for (const string& word : words) {
        cout << "  " << word << endl;
    }

    cout << "\nWords with prefix 'ban':" << endl;
    words = trie.getWordsWithPrefix("ban");
    for (const string& word : words) {
        cout << "  " << word << endl;
    }

    // Print all words
    cout << "\nAll words in Trie:" << endl;
    trie.printAllWords();

    // Delete a word
    cout << "\nDeleting 'app'..." << endl;
    trie.deleteWord("app");

    cout << "Searching 'app' after deletion: " 
         << (trie.search("app") ? "Found" : "Not Found") << endl;
    cout << "Searching 'apple' after deletion: " 
         << (trie.search("apple") ? "Found" : "Not Found") << endl;

    return 0;
}
```

