## Key Features:

1. **insert()** - O(m) where m is word length
2. **search()** - O(m)
3. **startsWith()** - O(m)
4. **deleteWord()** - O(m)
5. **printAllWords()** - O(n*m) where n is number of words
6. **getWordsWithPrefix()** - Returns all words starting with a prefix

This implementation is efficient and handles all common Trie operations!

# Trie Implementation in C++ using std::vector

Here's a complete implementation of a Trie data structure using `std::vector`:

```cpp
#include <iostream>
#include <vector>
#include <string>
using namespace std;

class TrieNode {
public:
    vector<TrieNode*> children;  // 26 children for 'a' to 'z'
    bool isEndOfWord;            // marks if this node is end of a word

    TrieNode() : isEndOfWord(false) {
        children.resize(26, nullptr);  // Initialize with 26 null pointers
    }

    ~TrieNode() {
        for (TrieNode* child : children) {
            delete child;
        }
    }
};

class Trie {
private:
    TrieNode* root;

public:
    Trie() {
        root = new TrieNode();
    }

    ~Trie() {
        delete root;
    }

    // Insert a word into the Trie
    void insert(const string& word) {
        TrieNode* node = root;

        for (char c : word) {
            int index = c - 'a';  // Convert char to index (0-25)

            if (node->children[index] == nullptr) {
                node->children[index] = new TrieNode();
            }

            node = node->children[index];
        }

        node->isEndOfWord = true;
    }

    // Search for an exact word
    bool search(const string& word) {
        TrieNode* node = find(word);
        return node != nullptr && node->isEndOfWord;
    }

    // Search for words with a given prefix
    bool startsWith(const string& prefix) {
        return find(prefix) != nullptr;
    }

    // Delete a word from the Trie
    bool deleteWord(const string& word) {
        return deleteHelper(root, word, 0);
    }

    // Display all words in the Trie (in-order traversal)
    void displayAll() {
        string current = "";
        displayHelper(root, current);
    }

private:
    // Helper function to find a node
    TrieNode* find(const string& prefix) {
        TrieNode* node = root;

        for (char c : prefix) {
            int index = c - 'a';

            if (node->children[index] == nullptr) {
                return nullptr;
            }

            node = node->children[index];
        }

        return node;
    }

    // Helper function to delete a word recursively
    bool deleteHelper(TrieNode* node, const string& word, int index) {
        if (index == word.length()) {
            if (!node->isEndOfWord) {
                return false;  // Word doesn't exist
            }

            node->isEndOfWord = false;
            return true;
        }

        int charIndex = word[index] - 'a';
        TrieNode* child = node->children[charIndex];

        if (child == nullptr) {
            return false;  // Word doesn't exist
        }

        bool shouldDeleteChild = deleteHelper(child, word, index + 1);

        if (shouldDeleteChild) {
            // Delete child if it has no children and is not end of another word
            bool hasOtherChildren = false;
            for (TrieNode* grandchild : child->children) {
                if (grandchild != nullptr) {
                    hasOtherChildren = true;
                    break;
                }
            }

            if (!hasOtherChildren && !child->isEndOfWord) {
                delete child;
                node->children[charIndex] = nullptr;

                // Check if current node should be deleted
                for (TrieNode* sibling : node->children) {
                    if (sibling != nullptr) {
                        return false;
                    }
                }
                return !node->isEndOfWord;
            }
        }

        return false;
    }

    // Helper function to display all words
    void displayHelper(TrieNode* node, string& current) {
        if (node->isEndOfWord) {
            cout << current << endl;
        }

        for (int i = 0; i < 26; i++) {
            if (node->children[i] != nullptr) {
                current.push_back('a' + i);
                displayHelper(node->children[i], current);
                current.pop_back();
            }
        }
    }
};

// Example usage
int main() {
    Trie trie;

    // Insert words
    cout << "=== Inserting words ===" << endl;
    vector<string> words = {"apple", "app", "application", "apply", "bat", "batman", "ball"};

    for (const string& word : words) {
        trie.insert(word);
        cout << "Inserted: " << word << endl;
    }

    // Search for words
    cout << "\n=== Searching for words ===" << endl;
    cout << "Search 'apple': " << (trie.search("apple") ? "Found" : "Not Found") << endl;
    cout << "Search 'app': " << (trie.search("app") ? "Found" : "Not Found") << endl;
    cout << "Search 'appl': " << (trie.search("appl") ? "Found" : "Not Found") << endl;
    cout << "Search 'xyz': " << (trie.search("xyz") ? "Found" : "Not Found") << endl;

    // Check prefixes
    cout << "\n=== Checking prefixes ===" << endl;
    cout << "Prefix 'app': " << (trie.startsWith("app") ? "Found" : "Not Found") << endl;
    cout << "Prefix 'bat': " << (trie.startsWith("bat") ? "Found" : "Not Found") << endl;
    cout << "Prefix 'car': " << (trie.startsWith("car") ? "Found" : "Not Found") << endl;

    // Display all words
    cout << "\n=== All words in Trie ===" << endl;
    trie.displayAll();

    // Delete a word
    cout << "\n=== Deleting 'app' ===" << endl;
    trie.deleteWord("app");
    cout << "Search 'app': " << (trie.search("app") ? "Found" : "Not Found") << endl;

    // Display all words after deletion
    cout << "\n=== All words after deletion ===" << endl;
    trie.displayAll();

    return 0;
}
```

