## Key Features:

1. **TrieNode**: Uses `vector<TrieNode*>` to store 26 children (a-z)
2. **insert()**: Adds a word to the Trie - O(m) where m is word length
3. **search()**: Finds exact word match - O(m)
4. **startsWith()**: Checks if prefix exists - O(m)
5. **deleteWord()**: Removes a word and cleans up unused nodes - O(m)
6. **displayAll()**: Displays all words using DFS traversal

This implementation is efficient and memory-friendly when storing many words with common prefixes!

# Trie Implementation in C++ using std::vector

Here's a complete implementation of a Trie data structure using `std::vector`:

```cpp
#include <iostream>
#include <vector>
#include <string>

using namespace std;

class TrieNode {
public:
    vector<TrieNode*> children;  // 26 children for 'a' to 'z'
    bool isEndOfWord;            // Mark end of a word

    TrieNode() : isEndOfWord(false) {
        children.resize(26, nullptr);  // Initialize with 26 nullptr pointers
    }
};

class Trie {
private:
    TrieNode* root;

public:
    // Constructor
    Trie() {
        root = new TrieNode();
    }

    // Destructor
    ~Trie() {
        deleteTrie(root);
    }

    // Insert a word into the Trie
    void insert(const string& word) {
        TrieNode* current = root;

        for (char c : word) {
            int index = c - 'a';  // Convert char to index (0-25)

            // If child doesn't exist, create it
            if (current->children[index] == nullptr) {
                current->children[index] = new TrieNode();
            }

            current = current->children[index];
        }

        // Mark the end of the word
        current->isEndOfWord = true;
    }

    // Search for a complete word in the Trie
    bool search(const string& word) const {
        TrieNode* current = root;

        for (char c : word) {
            int index = c - 'a';

            if (current->children[index] == nullptr) {
                return false;
            }

            current = current->children[index];
        }

        return current->isEndOfWord;
    }

    // Check if there's any word starting with the given prefix
    bool startsWith(const string& prefix) const {
        TrieNode* current = root;

        for (char c : prefix) {
            int index = c - 'a';

            if (current->children[index] == nullptr) {
                return false;
            }

            current = current->children[index];
        }

        return true;  // Prefix found
    }

    // Delete a word from the Trie
    bool deleteWord(const string& word) {
        return deleteHelper(root, word, 0);
    }

    // Display all words in the Trie
    void displayAllWords() const {
        string word = "";
        displayHelper(root, word);
    }

private:
    // Helper function to delete a word
    bool deleteHelper(TrieNode* node, const string& word, int index) {
        if (index == word.length()) {
            if (!node->isEndOfWord) {
                return false;  // Word not found
            }
            node->isEndOfWord = false;
            return true;
        }

        int charIndex = word[index] - 'a';

        if (node->children[charIndex] == nullptr) {
            return false;  // Word not found
        }

        bool shouldDeleteChild = deleteHelper(node->children[charIndex], word, index + 1);

        if (shouldDeleteChild) {
            // Delete child if it has no children and is not end of another word
            if (node->children[charIndex]->isEndOfWord == false && 
                isEmpty(node->children[charIndex])) {
                delete node->children[charIndex];
                node->children[charIndex] = nullptr;
            }
        }

        return shouldDeleteChild;
    }

    // Helper function to check if a node is empty (has no children)
    bool isEmpty(TrieNode* node) const {
        for (int i = 0; i < 26; i++) {
            if (node->children[i] != nullptr) {
                return false;
            }
        }
        return true;
    }

    // Helper function to display all words
    void displayHelper(TrieNode* node, string& word) const {
        if (node == nullptr) {
            return;
        }

        if (node->isEndOfWord) {
            cout << word << endl;
        }

        for (int i = 0; i < 26; i++) {
            if (node->children[i] != nullptr) {
                word.push_back(char('a' + i));
                displayHelper(node->children[i], word);
                word.pop_back();
            }
        }
    }

    // Helper function to delete entire Trie
    void deleteTrie(TrieNode* node) {
        if (node == nullptr) {
            return;
        }

        for (int i = 0; i < 26; i++) {
            if (node->children[i] != nullptr) {
                deleteTrie(node->children[i]);
            }
        }

        delete node;
    }
};

// Main function with examples
int main() {
    Trie trie;

    // Insert words
    cout << "Inserting words: apple, app, apricot, bat, ball, banana\n\n";
    trie.insert("apple");
    trie.insert("app");
    trie.insert("apricot");
    trie.insert("bat");
    trie.insert("ball");
    trie.insert("banana");

    // Search for words
    cout << "Search Results:\n";
    cout << "Search 'apple': " << (trie.search("apple") ? "Found" : "Not Found") << endl;
    cout << "Search 'app': " << (trie.search("app") ? "Found" : "Not Found") << endl;
    cout << "Search 'appl': " << (trie.search("appl") ? "Found" : "Not Found") << endl;
    cout << "Search 'bat': " << (trie.search("bat") ? "Found" : "Not Found") << endl;
    cout << "Search 'cat': " << (trie.search("cat") ? "Found" : "Not Found") << endl << endl;

    // Prefix search
    cout << "Prefix Search Results:\n";
    cout << "Prefix 'app': " << (trie.startsWith("app") ? "Found" : "Not Found") << endl;
    cout << "Prefix 'ba': " << (trie.startsWith("ba") ? "Found" : "Not Found") << endl;
    cout << "Prefix 'ca': " << (trie.startsWith("ca") ? "Found" : "Not Found") << endl << endl;

    // Display all words
    cout << "All Words in Trie:\n";
    trie.displayAllWords();

    cout << "\nDeleting 'app'...\n";
    trie.deleteWord("app");

    cout << "All Words after deletion:\n";
    trie.displayAllWords();

    return 0;
}
