## Key Features:

1. **TrieNode class**: Contains a vector of 26 pointers and a boolean flag
2. **insert()**: Add words to the Trie - O(m) where m is word length
3. **search()**: Find exact word - O(m)
4. **startsWith()**: Check prefix - O(m)
5. **deleteWord()**: Remove words efficiently
6. **displayAllWords()**: Print all stored words
7. **Memory management**: Proper cleanup in destructor

This implementation is efficient for autocomplete, spell checking, and word search applications!

# Trie Implementation in C++ using std::vector

Here's a complete implementation of a Trie data structure using `std::vector`:

```cpp
#include <iostream>
#include <vector>
#include <string>
using namespace std;

class TrieNode {
public:
    vector<TrieNode*> children;  // 26 pointers for 'a' to 'z'
    bool isEndOfWord;

    TrieNode() : isEndOfWord(false) {
        children.resize(26, nullptr);  // Initialize with 26 null pointers
    }
};

class Trie {
private:
    TrieNode* root;

public:
    Trie() {
        root = new TrieNode();
    }

    ~Trie() {
        deleteTrie(root);
    }

    // Insert a word into the Trie
    void insert(string word) {
        TrieNode* current = root;

        for (char c : word) {
            int index = c - 'a';  // Convert char to index (0-25)

            if (current->children[index] == nullptr) {
                current->children[index] = new TrieNode();
            }
            current = current->children[index];
        }

        current->isEndOfWord = true;
    }

    // Search for an exact word
    bool search(string word) {
        TrieNode* node = findNode(word);
        return node != nullptr && node->isEndOfWord;
    }

    // Search for words with prefix (returns true if prefix exists)
    bool startsWith(string prefix) {
        return findNode(prefix) != nullptr;
    }

    // Delete a word from the Trie
    bool deleteWord(string word) {
        return deleteHelper(root, word, 0);
    }

    // Print all words in the Trie
    void printAllWords() {
        string word = "";
        printHelper(root, word);
    }

private:
    // Helper function to find a node
    TrieNode* findNode(string prefix) {
        TrieNode* current = root;

        for (char c : prefix) {
            int index = c - 'a';

            if (current->children[index] == nullptr) {
                return nullptr;
            }
            current = current->children[index];
        }

        return current;
    }

    // Recursive helper for deletion
    bool deleteHelper(TrieNode* node, string word, int index) {
        if (index == word.length()) {
            if (!node->isEndOfWord) {
                return false;  // Word doesn't exist
            }
            node->isEndOfWord = false;

            // Return true if node has no children (can be deleted)
            for (TrieNode* child : node->children) {
                if (child != nullptr) return false;
            }
            return true;
        }

        int charIndex = word[index] - 'a';
        TrieNode* child = node->children[charIndex];

        if (child == nullptr) {
            return false;  // Word doesn't exist
        }

        bool shouldDeleteChild = deleteHelper(child, word, index + 1);

        if (shouldDeleteChild) {
            node->children[charIndex] = nullptr;
            delete child;

            // Delete current node if it has no children and isn't end of another word
            if (!node->isEndOfWord) {
                for (TrieNode* c : node->children) {
                    if (c != nullptr) return false;
                }
                return true;
            }
        }

        return false;
    }

    // Helper function to print all words
    void printHelper(TrieNode* node, string word) {
        if (node == nullptr) return;

        if (node->isEndOfWord) {
            cout << word << endl;
        }

        for (int i = 0; i < 26; i++) {
            if (node->children[i] != nullptr) {
                printHelper(node->children[i], word + char('a' + i));
            }
        }
    }

    // Helper function to delete the entire Trie
    void deleteTrie(TrieNode* node) {
        if (node == nullptr) return;

        for (TrieNode* child : node->children) {
            deleteTrie(child);
        }

        delete node;
    }
};

// Demo and Test Cases
int main() {
    Trie trie;

    // Insert words
    cout << "=== Inserting words ===" << endl;
    trie.insert("apple");
    trie.insert("app");
    trie.insert("application");
    trie.insert("apply");
    trie.insert("banana");
    trie.insert("band");
    trie.insert("can");
    trie.insert("cat");
    trie.insert("dog");

    // Search for words
    cout << "\n=== Searching for words ===" << endl;
    cout << "Search 'apple': " << (trie.search("apple") ? "Found" : "Not found") << endl;
    cout << "Search 'app': " << (trie.search("app") ? "Found" : "Not found") << endl;
    cout << "Search 'appl': " << (trie.search("appl") ? "Found" : "Not found") << endl;
    cout << "Search 'dog': " << (trie.search("dog") ? "Found" : "Not found") << endl;
    cout << "Search 'dodge': " << (trie.search("dodge") ? "Found" : "Not found") << endl;

    // Search for prefixes
    cout << "\n=== Searching for prefixes ===" << endl;
    cout << "StartsWith 'app': " << (trie.startsWith("app") ? "True" : "False") << endl;
    cout << "StartsWith 'ban': " << (trie.startsWith("ban") ? "True" : "False") << endl;
    cout << "StartsWith 'xyz': " << (trie.startsWith("xyz") ? "True" : "False") << endl;

    // Print all words
    cout << "\n=== All words in Trie ===" << endl;
    trie.printAllWords();

    // Delete a word
    cout << "\n=== Deleting 'app' ===" << endl;
    cout << "Delete 'app': " << (trie.deleteWord("app") ? "Success" : "Failed") << endl;
    cout << "Search 'app' after deletion: " << (trie.search("app") ? "Found" : "Not found") << endl;
    cout << "Search 'apple' after deleting 'app': " << (trie.search("apple") ? "Found" : "Not found") << endl;

    cout << "\n=== All words after deletion ===" << endl;
    trie.printAllWords();

    return 0;
}
```

