## Key Features:

1. **TrieNode Class**: Uses `std::vector<TrieNode*>` to store 26 children (for a-z)
2. **insert()**: O(m) where m is word length
3. **search()**: O(m) exact word search
4. **startsWith()**: O(m) prefix search
5. **deleteWord()**: O(m) with recursive cleanup
6. **printAllWords()**: DFS traversal to print all stored words
7. **Memory Management**: Proper destructor for cleanup

This implementation is efficient and suitable for applications like autocomplete, spell checking, and IP routing!

# Trie Implementation in C++ using std::vector

Here's a complete implementation of a Trie data structure using `std::vector`:

```cpp
#include <iostream>
#include <vector>
#include <string>
using namespace std;

class TrieNode {
public:
    vector<TrieNode*> children;
    bool isEndOfWord;

    TrieNode() : isEndOfWord(false) {
        children.resize(26, nullptr);  // 26 letters in alphabet
    }
};

class Trie {
private:
    TrieNode* root;

public:
    Trie() {
        root = new TrieNode();
    }

    ~Trie() {
        deleteTrie(root);
    }

    // Insert a word into the trie
    void insert(const string& word) {
        TrieNode* current = root;

        for (char c : word) {
            int index = c - 'a';  // Convert char to index (0-25)

            if (current->children[index] == nullptr) {
                current->children[index] = new TrieNode();
            }
            current = current->children[index];
        }
        current->isEndOfWord = true;
    }

    // Search for a complete word
    bool search(const string& word) const {
        TrieNode* node = findNode(word);
        return (node != nullptr && node->isEndOfWord);
    }

    // Check if there is any word with given prefix
    bool startsWith(const string& prefix) const {
        return findNode(prefix) != nullptr;
    }

    // Delete a word from the trie
    bool deleteWord(const string& word) {
        return deleteHelper(root, word, 0);
    }

    // Print all words in the trie
    void printAllWords() const {
        string current = "";
        printHelper(root, current);
    }

    // Get all words with a given prefix
    vector<string> getWordsWithPrefix(const string& prefix) const {
        vector<string> result;
        TrieNode* node = findNode(prefix);

        if (node != nullptr) {
            string current = prefix;
            collectWords(node, current, result);
        }
        return result;
    }

private:
    TrieNode* findNode(const string& prefix) const {
        TrieNode* current = root;

        for (char c : prefix) {
            int index = c - 'a';
            if (current->children[index] == nullptr) {
                return nullptr;
            }
            current = current->children[index];
        }
        return current;
    }

    bool deleteHelper(TrieNode* node, const string& word, int index) {
        if (index == word.length()) {
            if (!node->isEndOfWord) {
                return false;  // Word not found
            }
            node->isEndOfWord = false;
            return true;
        }

        int charIndex = word[index] - 'a';
        if (node->children[charIndex] == nullptr) {
            return false;  // Word not found
        }

        bool shouldDeleteChild = deleteHelper(
            node->children[charIndex], word, index + 1
        );

        if (shouldDeleteChild) {
            delete node->children[charIndex];
            node->children[charIndex] = nullptr;
        }

        return shouldDeleteChild && !node->isEndOfWord && 
               hasNoChildren(node);
    }

    bool hasNoChildren(TrieNode* node) const {
        for (TrieNode* child : node->children) {
            if (child != nullptr) return false;
        }
        return true;
    }

    void printHelper(TrieNode* node, string& current) const {
        if (node->isEndOfWord) {
            cout << current << "\n";
        }

        for (int i = 0; i < 26; i++) {
            if (node->children[i] != nullptr) {
                current.push_back('a' + i);
                printHelper(node->children[i], current);
                current.pop_back();
            }
        }
    }

    void collectWords(TrieNode* node, string& current, 
                     vector<string>& result) const {
        if (node->isEndOfWord) {
            result.push_back(current);
        }

        for (int i = 0; i < 26; i++) {
            if (node->children[i] != nullptr) {
                current.push_back('a' + i);
                collectWords(node->children[i], current, result);
                current.pop_back();
            }
        }
    }

    void deleteTrie(TrieNode* node) {
        if (node == nullptr) return;

        for (TrieNode* child : node->children) {
            deleteTrie(child);
        }
        delete node;
    }
};

// Example usage
int main() {
    Trie trie;

    // Insert words
    trie.insert("apple");
    trie.insert("app");
    trie.insert("application");
    trie.insert("apply");
    trie.insert("banana");
    trie.insert("band");
    trie.insert("can");
    trie.insert("cat");

    cout << "=== All words in Trie ===" << "\n";
    trie.printAllWords();

    cout << "\n=== Search Operations ===" << "\n";
    cout << "Search 'apple': " << (trie.search("apple") ? "Found" : "Not found") << "\n";
    cout << "Search 'app': " << (trie.search("app") ? "Found" : "Not found") << "\n";
    cout << "Search 'appl': " << (trie.search("appl") ? "Found" : "Not found") << "\n";

    cout << "\n=== Prefix Operations ===" << "\n";
    cout << "Words with prefix 'app': ";
    vector<string> appWords = trie.getWordsWithPrefix("app");
    for (const string& word : appWords) {
        cout << word << " ";
    }
    cout << "\n";

    cout << "Words with prefix 'ba': ";
    vector<string> baWords = trie.getWordsWithPrefix("ba");
    for (const string& word : baWords) {
        cout << word << " ";
    }
    cout << "\n";

    cout << "\n=== StartsWith Operation ===" << "\n";
    cout << "StartsWith 'ban': " << (trie.startsWith("ban") ? "True" : "False") << "\n";
    cout << "StartsWith 'xyz': " << (trie.startsWith("xyz") ? "True" : "False") << "\n";

    cout << "\n=== Delete Operation ===" << "\n";
    cout << "Delete 'app': " << (trie.deleteWord("app") ? "Deleted" : "Not found") << "\n";
    cout << "Search 'app' after deletion: " 
         << (trie.search("app") ? "Found" : "Not found") << "\n";
    cout << "Search 'apple' after deleting 'app': " 
         << (trie.search("apple") ? "Found" : "Not found") << "\n";

    return 0;
}
```

